  "scenarioId": "eval-complex-human-planning-and-match",
  "extraction": {
    "title": "HubSpot support and sales ops migration with automations, handoff docs, and operator training",
    "summary": "Migrate support ops from Notion and Airtable to HubSpot, including proper setup of automations, handoff documentation, and training so the client team can operate it later (avoid black-box). Budget is around 6k–9k and timeline is ~3 weeks. AI support is acceptable.",
    "seeking": {
      "actorKinds": [
        "human"
