      "migration_plan",
      "workflow_build",
      "handoff_doc",
      "operator_training"
    ],
    "missingDetails": [
      "Which HubSpot modules are in scope (e.g., Sales Hub, Service Hub, CRM properties, workflows)?",
      "Whether the migration includes existing customer/support history from Notion/Airtable (fields, volume, and mapping).",
      "Any access constraints and data export/import method details for Notion and Airtable to HubSpot.",
      "Preferred handoff format for automations (how-to docs, runbooks, and ownership model)."
    ],
    "constraints": {
      "avoid_black_box_setup": true,
      "allow_ai_support": true,
      "budgetCurrency": "USD",
      "budgetMin": 6000,
      "budgetMax": 9000,
      "timeWindow": {
        "label": "about_3_weeks"
      },
      "current_tools": [
        "Notion",
        "Airtable"
      ],
      "target_tool": "HubSpot"
    }
  },
  "routing": {
    "routeFamily": "direct_specialist",
