      "riskLevel": "medium",
      "reasons": [
        "Data mapping and HubSpot module scope are not specified; execution could fail without confirming what 'properly set up' includes.",
        "Automation expectations and operator-run requirements imply deliverables that must be aligned early to avoid a black-box outcome."
      ]
    },
    "phases": [
      {
        "phaseKey": "phase_1_discovery_and_scope",
        "title": "Confirm HubSpot scope and migration ownership requirements (avoid black-box), and define what 'operators can run later' means."
      },
      {
        "phaseKey": "phase_2_migration_design_and_build",
        "title": "Design the migration approach and build HubSpot configuration/automations for support handoffs."
      },
      {
